[T_{\tau x}, T_{\tau y}] &= -T_{xy} \\
[T_{\tau x}, -T_{t_x t_z}] &= -[T_{\tau x}, T_{t_x t_z}] = -(\delta_{x,t_x}T_{\tau t_z} - \delta_{\tau,t_x}T_{xt_z} - \delta_{x,t_z}T_{\tau t_x} + \delta_{\tau,t_z}T_{xt_x}) \\
